function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const graph: Map<number, Array<[number, number]>> = new Map();
    for (const [u, v, w] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u)!.push([v, w]);
    }

    // Priority queue for Dijkstra's algorithm: (cost, node, switch_used)
    // switch_used is a boolean indicating whether the switch at the node has been used
    const pq: [number, number, boolean][] = [(0, 0, false)];  // (cost, node, switch_used)
    const visited: Set<string> = new Set();  // (node, switch_used)

    while (pq.length > 0) {
        const [cost, node, switchUsed] = pq.shift()!;

        // If we've reached the destination
        if (node === n - 1) {
            return cost;
        }

        // If we've already visited this node with the same switch state
        const key = `${node},${switchUsed}`;
        if (visited.has(key)) {
            continue;
        }
        visited.add(key);

        // Explore neighbors
        if (graph.has(node)) {
            for (const [neighbor, weight] of graph.get(node)! as [number, number][]) {
                // Normal edge
                const newCost = cost + weight;
                const newKey = `${neighbor},false`;
                if (!visited.has(newKey)) {
                    pq.push([newCost, neighbor, false]);
                }

                // Reverse edge (if switch hasn't been used)
                if (!switchUsed) {
                    const newCostRev = cost + 2 * weight;
                    const newKeyRev = `${neighbor},true`;
                    if (!visited.has(newKeyRev)) {
                        pq.push([newCostRev, neighbor, true]);
                    }
                }
            }
        }
    }

    return -1;
}
